  const getTopSalts = () => {
    const saltCounts: Record<string, number> = {};
    moleculeData.forEach(item => {
      const salt = item['Electrolytes.Salts.Name'];
      if (salt) {
        saltCounts[salt] = (saltCounts[salt] || 0) + 1;
      }
    });
    return Object.entries(saltCounts)
      .sort(([,a], [,b]) => b - a)
      .slice(0, 5)
      .map(([salt]) => salt);
  };

