    return values.length > 0 ? (values.reduce((a, b) => a + b, 0) / values.length).toFixed(1) : '0.0';
  };

  const getAverageLUMO = () => {
    const values = moleculeData
      .map(item => {
        const lumoStr = item['Properties of electrolyte.LUMO energy level'];
        if (lumoStr && typeof lumoStr === 'string') {
          const match = lumoStr.match(/([\d.]+)\s*eV/);
          return match ? parseFloat(match[1]) : null;
        }
        return null;
      })
      .filter(val => val !== null) as number[];
    return values.length > 0 ? (values.reduce((a, b) => a + b, 0) / values.length).toFixed(2) : '0.00';
