    if (confidence >= 0.5) return 'orange';
    return 'red';
  };

  const columns: ColumnsType<Literature> = [
    {
      title: '标题',
      dataIndex: 'title',
      key: 'title',
      width: 300,
      ellipsis: true,
      render: (text: string, record: Literature) => (
        <Tooltip title={text}>
          <Button type="link" onClick={() => setSelectedLiterature(record)}>
            {text}
          </Button>
        </Tooltip>
      )
    },
    {
      title: '作者',
      dataIndex: 'authors',
      key: 'authors',
      width: 200,
      ellipsis: true
    },
    {
      title: '期刊',
      dataIndex: 'journal',
      key: 'journal',
      width: 150,
      ellipsis: true
    },
    {
      title: '年份',
      dataIndex: 'publication_year',
      key: 'publication_year',
      width: 80,
      sorter: true
    },
    {
      title: '处理状态',
      dataIndex: 'processing_status',
      key: 'processing_status',
      width: 100,
      render: (status: string) => (
        <Tag color={getStatusColor(status)}>
          {status.toUpperCase()}
        </Tag>
      ),
      filters: [
        { text: '待处理', value: 'pending' },
        { text: '处理中', value: 'processing' },
        { text: '已完成', value: 'completed' },
        { text: '失败', value: 'failed' }
      ]
    },
    {
      title: '提取置信度',
      dataIndex: 'extraction_confidence',
      key: 'extraction_confidence',
      width: 120,
      render: (confidence: number) => (
        <Progress
          percent={Math.round(confidence * 100)}
          size="small"
          status={confidence >= 0.5 ? 'success' : 'exception'}
        />
      ),
      sorter: true
    },
    {
      title: '相关性评分',
      dataIndex: 'relevance_score',
      key: 'relevance_score',
      width: 120,
      render: (score: number) => (
        <Tag color={getConfidenceColor(score)}>
          {(score * 100).toFixed(1)}%
        </Tag>
      )
    },
    {
      title: '关联配方',
      key: 'formulas',
      width: 100,
      render: (_, record: Literature) => (
        <span>{record.associated_formulas?.length || 0}</span>
      )
    },
    {
      title: '操作',
      key: 'actions',
      width: 150,
      render: (_, record: Literature) => (
        <Space>
          <Button size="small" onClick={() => setSelectedLiterature(record)}>
            详情
          </Button>
          {record.processed && (
            <Button size="small" type="primary">
              查看配方
            </Button>
          )}
        </Space>
      )
    }
  ];

  return (
    <div style={{ padding: '24px' }}>
      <Card>
        <div style={{ marginBottom: 16 }}>
          <Row gutter={16} justify="space-between" align="middle">
            <Col>
              <h2>文献管理</h2>
              <div style={{ marginTop: 8 }}>
                <Space>
                  <span>显示SicPDF文献:</span>
                  <Switch
                    checked={showSicPDF}
                    onChange={setShowSicPDF}
                    checkedChildren="SicPDF"
                    unCheckedChildren="数据库"
                  />
                </Space>
              </div>
            </Col>
            <Col>
              <Space>
                <Button
                  icon={<UploadOutlined />}
                  onClick={() => setUploadModalVisible(true)}
                >
                  上传PDF
                </Button>
                <Button
                  icon={<DatabaseOutlined />}
                  onClick={() => setProcessModalVisible(true)}
                >
                  处理文献
                </Button>
                <Button
                  icon={<SearchOutlined />}
                  onClick={() => setSearchModalVisible(true)}
                >
                  搜索文献
                </Button>
                <Button
                  icon={<ReloadOutlined />}
                  onClick={() => {
                    loadLiterature();
                    loadStats();
                  }}
                >
                  刷新
                </Button>
              </Space>
            </Col>
          </Row>
        </div>

        {/* 文献列表和筛选区域 */}
        <div style={{ marginBottom: 16 }}>
          <Space>
            <span>筛选状态:</span>
            <Select
              style={{ width: 120 }}
              value={filters.status}
              onChange={(value) => setFilters(prev => ({ ...prev, status: value }))}
              allowClear
            >
              <Option value="pending">待处理</Option>
              <Option value="processing">处理中</Option>
              <Option value="completed">已完成</Option>
              <Option value="failed">失败</Option>
            </Select>
            <span>最小置信度:</span>
            <Select
              style={{ width: 100 }}
              value={filters.min_confidence}
              onChange={(value) => setFilters(prev => ({ ...prev, min_confidence: value }))}
            >
              <Option value={0.0}>全部</Option>
              <Option value={0.3}>30%</Option>
              <Option value={0.5}>50%</Option>
              <Option value={0.8}>80%</Option>
            </Select>
          </Space>
        </div>

        <Table
          columns={columns}
          dataSource={literature}
          rowKey="id"
          loading={loading}
          pagination={{
            ...pagination,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total) => `共 ${total} 条记录`,
            onChange: (page, pageSize) => {
              setPagination(prev => ({ ...prev, current: page, pageSize: pageSize || 20 }));
            }
          }}
          scroll={{ x: 1200 }}
        />

        {/* 统计信息和分子数据展示区域 */}
        {(showMoleculeData || showSicPDF) && (
          <div style={{ marginTop: 24 }}>
            <Row gutter={[16, 16]}>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="总文献数"
                    value={showSicPDF ? sicPDFData.length : (stats?.total_literature || 0)}
                    prefix={<DatabaseOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="已处理文献"
                    value={showSicPDF ? sicPDFData.filter(l => l.processed).length : (stats?.processed_literature || 0)}
                    valueStyle={{ color: '#3f8600' }}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="待处理文献"
                    value={showSicPDF ? sicPDFData.filter(l => !l.processed).length : (stats?.unprocessed_literature || 0)}
                    valueStyle={{ color: '#cf1322' }}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="提取配方数"
                    value={showMoleculeData ? moleculeData.length : (stats?.total_extracted_formulas || 0)}
                    prefix={<FileTextOutlined />}
                  />
                </Card>
              </Col>
            </Row>

            <div style={{ marginTop: 16 }}>
              <Card title="置信度分布">
                  {showSicPDF ? (
                    <div>
                      <div style={{ marginBottom: 8 }}>
                        <Tag color="orange">未处理 (0%)</Tag>
                        <span style={{ marginLeft: 8 }}>{sicPDFData.filter(l => l.extraction_confidence === 0).length} 篇</span>
                      </div>
                      <div style={{ marginBottom: 8 }}>
                        <Tag color="green">已处理 (&gt;70%)</Tag>
                        <span style={{ marginLeft: 8 }}>{sicPDFData.filter(l => l.extraction_confidence > 0.7).length} 篇</span>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div style={{ marginBottom: 8 }}>
                        <Tag color="green">高置信度 (≥80%)</Tag>
                        <span style={{ marginLeft: 8 }}>{stats?.confidence_distribution?.high || 0} 篇</span>
                      </div>
                      <div style={{ marginBottom: 8 }}>
                        <Tag color="orange">中置信度 (50-80%)</Tag>
                        <span style={{ marginLeft: 8 }}>{stats?.confidence_distribution?.medium || 0} 篇</span>
                      </div>
                      <div>
                        <Tag color="red">低置信度 (&lt;50%)</Tag>
                        <span style={{ marginLeft: 8 }}>{stats?.confidence_distribution?.low || 0} 篇</span>
                      </div>
                    </>
                  )}
                </Card>
            </div>
          </div>
        )}

        {/* 挖掘到的分子和配方数据 */}
        {showMoleculeData && moleculeData.length > 0 && (
          <div style={{ marginTop: 24 }}>
            <Card
              title={
                <span>
                  挖掘到的分子和配方数据
                  <Badge count={moleculeData.length} style={{ marginLeft: 8 }} />
                </span>
              }
            >
              <Table
                columns={[
                  {
                    title: 'URL',
                    dataIndex: 'url',
                    key: 'url',
                    width: 200,
                    ellipsis: true,
                    render: (text) => (
                      <Tooltip title={text}>
                        <a href={text} target="_blank" rel="noopener noreferrer">
                          {text}
                        </a>
                      </Tooltip>
                    )
                  },
                  {
                    title: '盐',
                    dataIndex: 'Electrolytes.Salts.Name',
                    key: 'salts',
                    width: 100,
                    ellipsis: true
                  },
                  {
                    title: '溶剂',
                    dataIndex: 'Electrolytes.Solvents.Name',
                    key: 'solvents',
                    width: 120,
                    ellipsis: true
                  },
                  {
                    title: '添加剂',
                    dataIndex: 'Electrolytes.Additives.Name',
                    key: 'additives',
                    width: 100,
                    ellipsis: true
                  },
                  {
                    title: '负极',
                    dataIndex: 'Anode.Name',
                    key: 'anode',
                    width: 100,
                    ellipsis: true
                  },
                  {
                    title: '正极',
                    dataIndex: 'Cathode.Name',
                    key: 'cathode',
                    width: 100,
                    ellipsis: true,
                    render: (text) => <Tag color="blue">{text}</Tag>
                  },
                  {
                    title: '电解液类型',
                    dataIndex: 'System of electrolyte.Type',
                    key: 'electrolyte_type',
                    width: 120,
                    ellipsis: true,
                    render: (text) => <Tag color="purple">{text}</Tag>
                  },
                  {
                    title: '能量密度',
                    key: 'energy_density',
                    width: 120,
                    render: (_, record) => (
                      <span style={{ fontWeight: 'bold', color: '#1890ff' }}>
                        {record['Performance.Energy density.Value']} {record['Performance.Energy density.Unit']}
                      </span>
                    )
                  },
                  {
                    title: '循环寿命',
                    key: 'cycle_lifespan',
                    width: 120,
                    render: (_, record) => (
                      <span style={{ fontWeight: 'bold', color: '#52c41a' }}>
                        {record['Performance.Cycle lifespan.Value']} {record['Performance.Cycle lifespan.Unit']}
                      </span>
                    )
                  },
                  {
                    title: '库伦效率',
                    key: 'coulombic_efficiency',
                    width: 120,
                    render: (_, record) => (
                      <Progress
                        percent={record['Performance.Coulombic efficiency.Value']}
                        size="small"
                        format={() => `${record['Performance.Coulombic efficiency.Value']}%`}
                      />
                    )
                  },
                  {
                    title: '倍率性能',
                    key: 'rate_performance',
                    width: 100,
                    render: (_, record) => (
                      <span>
                        {record['Performance.Rate performance.Value']} {record['Performance.Rate performance.Unit']}
                      </span>
                    )
                  },
                  {
                    title: 'LUMO能级',
                    key: 'lumo_level',
                    width: 100,
                    render: (_, record) => (
                      <span style={{ fontSize: '12px' }}>
                        {record['Properties of electrolyte.LUMO energy level.Value']} {record['Properties of electrolyte.LUMO energy level.Unit']}
                      </span>
                    )
                  },
                  {
                    title: '介电常数',
                    key: 'dielectric_constant',
                    width: 100,
                    render: (_, record) => (
                      <span style={{ fontSize: '12px' }}>
                        {record['Properties of electrolyte.Dielectric constant (ε).Value']}
                      </span>
                    )
                  }
                ]}
                dataSource={moleculeData}
                rowKey={(record, index) => `molecule-${index}`}
                pagination={{
                  current: moleculeDataPagination.current,
                  pageSize: moleculeDataPagination.pageSize,
                  showSizeChanger: true,
                  showQuickJumper: true,
                  showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条记录`,
                  onChange: (page, pageSize) => {
                    setMoleculeDataPagination({
                      current: page,
                      pageSize: pageSize || 10
                    });
                  },
                  onShowSizeChange: (current, size) => {
                    setMoleculeDataPagination({
                      current: current,
                      pageSize: size
                    });
                  }
                }}
                scroll={{ x: 1400 }}
                size="small"
              />
            </Card>
          </div>
        )}
      </Card>

      {/* 分子生成与优化界面 */}
      <div style={{ marginTop: 24 }}>
        <Card
          title={
            <span>
              <DatabaseOutlined style={{ marginRight: 8, color: '#52c41a' }} />
              分子生成与优化系统
              <Badge count="AI" style={{ marginLeft: 8, backgroundColor: '#52c41a' }} />
            </span>
          }
          extra={
            <Space>
              <Button
                type="primary"
                icon={<ExperimentOutlined />}
                onClick={() => handleGenerateMolecules()}
                loading={generateLoading}
              >
                生成新分子
              </Button>
              <Button
                icon={<ReloadOutlined />}
                onClick={() => handleOptimizeFormulas()}
                loading={optimizeLoading}
              >
                优化配方
              </Button>
            </Space>
          }
        >
          <div style={{ padding: '20px 0' }}>
            <Row gutter={[24, 24]}>
              <Col span={12}>
                <Card
                  size="small"
                  title="生成参数设置"
                  style={{ height: '100%' }}
                >
                  <Form layout="vertical">
                    <Form.Item label="目标性能指标">
                      <Select
                        mode="multiple"
                        placeholder="选择要优化的性能指标"
                        style={{ width: '100%' }}
                        value={selectedProperties}
                        onChange={setSelectedProperties}
                      >
                        <Option value="coulombic_efficiency">库伦效率</Option>
                        <Option value="rate_performance">倍率性能</Option>
                        <Option value="lumo_level">LUMO能级</Option>
                        <Option value="dielectric_constant">介电常数</Option>
                        <Option value="conductivity">电导率</Option>
                        <Option value="viscosity">粘度</Option>
                      </Select>
                    </Form.Item>

                    <Form.Item label="生成数量">
                      <InputNumber
                        min={1}
                        max={50}
                        value={generateCount}
                        onChange={(value: number | null) => setGenerateCount(value || 5)}
                        style={{ width: '100%' }}
                        placeholder="设置要生成的分子数量"
                      />
                    </Form.Item>

                    <Form.Item label="优化算法">
                      <Radio.Group
                        value={optimizationMethod}
                        onChange={(e) => setOptimizationMethod(e.target.value)}
                      >
                        <Radio value="genetic">遗传算法</Radio>
                        <Radio value="bayesian">贝叶斯优化</Radio>
                        <Radio value="reinforcement">强化学习</Radio>
                      </Radio.Group>
                    </Form.Item>

                    <Form.Item label="约束条件">
                      <Checkbox.Group
                        value={constraints}
                        onChange={setConstraints}
                      >
                        <Space direction="vertical">
                          <Checkbox value="toxicity">低毒性</Checkbox>
                          <Checkbox value="stability">高稳定性</Checkbox>
                          <Checkbox value="cost">低成本</Checkbox>
                          <Checkbox value="environmental">环境友好</Checkbox>
                        </Space>
                      </Checkbox.Group>
                    </Form.Item>
                  </Form>
                </Card>
              </Col>

              <Col span={12}>
                <Card
                  size="small"
                  title="基于挖掘数据的分析"
                  style={{ height: '100%' }}
                >
                  {moleculeData.length > 0 ? (
                    <>
                      <div style={{ marginBottom: 16 }}>
                        <Alert
                          message="基于当前挖掘结果"
                          description={`已从 ${moleculeData.length} 条配方数据中提取关键特征，准备进行分子生成优化。`}
                          type="info"
                          showIcon
                        />
                      </div>

                      <div style={{ marginBottom: 16 }}>
                        <h4>主要盐类分析：</h4>
                        <div style={{ maxHeight: 120, overflowY: 'auto' }}>
                          {getTopSalts().map((salt, index) => (
                            <Tag key={index} color="blue" style={{ margin: '4px 4px 4px 0' }}>
                              {salt} ({getSaltCount(salt)}次)
                            </Tag>
                          ))}
                        </div>
                      </div>

                      <div style={{ marginBottom: 16 }}>
                        <h4>性能分布：</h4>
                        <Row gutter={16}>
                          <Col span={12}>
                            <Statistic
                              title="平均库伦效率"
                              value={getAverageCoulombicEfficiency()}
                              suffix="%"
                              precision={1}
                            />
                          </Col>
                          <Col span={12}>
                            <Statistic
                              title="平均LUMO能级"
                              value={getAverageLUMO()}
                              suffix="eV"
                              precision={2}
                            />
                          </Col>
                        </Row>
                      </div>
                    </>
                  ) : (
                    <div style={{ textAlign: 'center', padding: '40px 0' }}>
                      <Alert
                        message="等待分子数据"
                        description="请先进行文献挖掘以获取分子和配方数据，然后即可使用分子生成功能。"
                        type="warning"
                        showIcon
                      />
                    </div>
                  )}

                  <div>
                    <Progress
                      percent={getAnalysisProgress()}
                      status={getAnalysisProgress() === 100 ? 'success' : 'active'}
                      format={() => getAnalysisProgress() === 100 ? '分析完成' : `${getAnalysisProgress()}%`}
                    />
                    <div style={{ textAlign: 'center', marginTop: 8, color: '#666' }}>
                      {getAnalysisProgress() === 100 ? '数据预处理完成，可开始分子生成' : '正在进行数据预处理...'}
                    </div>
                  </div>
                </Card>
              </Col>
            </Row>

            {/* 生成结果展示区域 */}
            {generatedMolecules.length > 0 && (
              <div style={{ marginTop: 24 }}>
                <Divider>生成的分子结果</Divider>
                <Table
                  columns={[
                    {
                      title: '序号',
                      dataIndex: 'index',
                      key: 'index',
                      width: 80,
                      render: (_, __, index) => index + 1
                    },
                    {
                      title: '分子结构',
                      dataIndex: 'structure',
                      key: 'structure',
                      width: 200,
                      render: (text) => (
                        <div style={{
                          textAlign: 'center',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          minHeight: '60px'
                        }}>
                          <div style={{
                            width: '100%',
                            maxWidth: '180px',
                            padding: '8px',
                            border: '1px solid #e8e8e8',
                            borderRadius: '4px',
                            backgroundColor: '#fafafa',
                            fontSize: '11px',
                            color: '#333',
                            fontFamily: 'Monaco, Consolas, monospace',
                            wordBreak: 'break-all',
                            lineHeight: '1.4',
                            textAlign: 'center'
                          }}>
                            {text === 'MOL_1' ? 'CC(C)OC(=O)C' :
                             text === 'MOL_2' ? 'CC1=CC=CC=C1C(=O)O' :
                             text === 'MOL_3' ? 'CCN(CC)CC' :
                             text === 'MOL_4' ? 'C1=CC=C(C=C1)O' :
                             text === 'MOL_5' ? 'CC(C)(C)OC(=O)O' :
                             text || 'N/A'}
                          </div>
                        </div>
                      )
                    },
                    {
                      title: '置信度',
                      dataIndex: 'confidence',
                      key: 'confidence',
                      width: 100,
                      render: (text) => (
                        <Progress
                          percent={text}
                          size="small"
                          strokeColor={text >= 80 ? '#52c41a' : text >= 60 ? '#faad14' : '#ff4d4f'}
                          format={() => `${text}%`}
                        />
                      ),
                      sorter: (a, b) => a.confidence - b.confidence
                    },
                    {
                      title: '预测性能',
                      dataIndex: 'performance',
                      key: 'performance',
                      width: 120,
                      render: (text) => (
                        <Tag color={text === '优秀' ? 'green' : text === '良好' ? 'blue' : 'orange'}>
                          {text}
                        </Tag>
                      )
                    },
                    {
                      title: '合成难度',
                      dataIndex: 'difficulty',
                      key: 'difficulty',
                      width: 120,
                      render: (text) => (
                        <Tag color={text === '简单' ? 'green' : text === '中等' ? 'blue' : 'red'}>
                          {text}
                        </Tag>
                      )
                    },
                    {
                      title: '库伦效率',
                      dataIndex: ['properties', 'coulombic_efficiency'],
                      key: 'coulombic_efficiency',
                      width: 120,
                      render: (text) => `${text}%`
                    },
                    {
                      title: 'LUMO能级',
                      dataIndex: ['properties', 'lumo_level'],
                      key: 'lumo_level',
                      width: 120,
                      render: (text) => `${text} eV`
                    },
                    {
                      title: '介电常数',
                      dataIndex: ['properties', 'dielectric_constant'],
                      key: 'dielectric_constant',
                      width: 120,
                      render: (text) => text
                    },
                    {
                      title: '操作',
                      key: 'actions',
                      width: 150,
                      render: (_, record, index) => {
                        // 计算在当前页面中的实际索引
                        const actualIndex = (generatedMoleculesPagination.current - 1) * generatedMoleculesPagination.pageSize + index;
                        return (
                          <Space>
                            <Button size="small" type="primary" ghost>
                              详细信息
                            </Button>
                            <Button size="small">
                              导出结构
                            </Button>
                            <Button
                              size="small"
                              danger
                              onClick={() => handleDeleteMolecule(actualIndex)}
                            >
                              删除
                            </Button>
                          </Space>
                        );
                      }
                    }
                  ]}
                  dataSource={generatedMolecules}
                  rowKey={(record, index) => `generated-${index}`}
                  pagination={{
                    current: generatedMoleculesPagination.current,
                    pageSize: generatedMoleculesPagination.pageSize,
                    showSizeChanger: true,
                    showQuickJumper: true,
                    showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 个分子`,
                    onChange: (page, pageSize) => {
                      setGeneratedMoleculesPagination({
                        current: page,
                        pageSize: pageSize || 10
                      });
                    },
                    onShowSizeChange: (current, size) => {
                      setGeneratedMoleculesPagination({
                        current: current,
                        pageSize: size
                      });
                    }
                  }}
                  scroll={{ x: 1200 }}
                  size="small"
                />
              </div>
            )}
          </div>
        </Card>
      </div>

      {/* 上传PDF模态框 */}
      <Modal
        title="上传PDF文件"
        visible={uploadModalVisible}
        onCancel={() => setUploadModalVisible(false)}
        footer={null}
        width={600}
      >
        <Upload
          accept=".pdf"
          multiple
          beforeUpload={(file, fileList) => {
            // 延迟执行以确保获取到所有选中的文件
            setTimeout(() => {
              handleUpload(fileList);
            }, 100);
            return false;
          }}
          showUploadList={true}
          directory={false}
        >
          <Button icon={<UploadOutlined />} size="large">
            选择PDF文件（支持多选）
          </Button>
        </Upload>
        <p style={{ marginTop: 16, color: '#666' }}>
          支持 PDF 格式，可选择多个文件同时上传。文件将保存到文献数据库中等待处理。
        </p>
        <div style={{ marginTop: 16 }}>
          <Alert
            message="上传提示"
            description="• 支持批量上传多个PDF文件&#10;• 单次最多可上传20个文件&#10;• 每个文件大小建议不超过50MB"
            type="info"
            showIcon
          />
        </div>
      </Modal>

      {/* 处理文献模态框 */}
      <Modal
        title="处理文献数据库"
        visible={processModalVisible}
        onCancel={() => setProcessModalVisible(false)}
        footer={null}
      >
        <Form onFinish={handleProcessLiterature}>
          <Form.Item
            name="pdf_directory"
            label="PDF目录"
            help="留空使用默认目录"
          >
            <Input placeholder="PDF文件目录路径" />
          </Form.Item>
          <Form.Item name="update_existing" valuePropName="checked">
            <Checkbox>更新已存在的记录</Checkbox>
          </Form.Item>
          <Form.Item name="batch_size" label="批处理大小" initialValue={5}>
            <Select>
              <Option value={3}>3</Option>
              <Option value={5}>5</Option>
              <Option value={10}>10</Option>
              <Option value={20}>20</Option>
            </Select>
          </Form.Item>
          <Form.Item>
            <Button type="primary" htmlType="submit" loading={loading}>
              开始处理
            </Button>
          </Form.Item>
        </Form>
      </Modal>

      {/* 搜索文献模态框 */}
      <Modal
        title="搜索文献"
        visible={searchModalVisible}
        onCancel={() => setSearchModalVisible(false)}
        footer={null}
      >
        <Form onFinish={handleSearch}>
          <Form.Item
            name="query"
            label="搜索关键词"
            rules={[{ required: true, message: '请输入搜索关键词' }]}
          >
            <Input placeholder="输入搜索关键词" />
          </Form.Item>
          <Form.Item name="component_type" label="组分类型">
            <Select allowClear>
              <Option value="solvent">溶剂</Option>
              <Option value="salt">盐</Option>
              <Option value="additive">添加剂</Option>
            </Select>
          </Form.Item>
          <Form.Item name="min_confidence" label="最小置信度" initialValue={0.5}>
            <Select>
              <Option value={0.3}>30%</Option>
              <Option value={0.5}>50%</Option>
              <Option value={0.8}>80%</Option>
            </Select>
          </Form.Item>
          <Form.Item name="limit" label="结果数量" initialValue={20}>
            <Select>
              <Option value={10}>10</Option>
              <Option value={20}>20</Option>
              <Option value={50}>50</Option>
              <Option value={100}>100</Option>
            </Select>
          </Form.Item>
          <Form.Item>
            <Button type="primary" htmlType="submit">
              搜索
            </Button>
          </Form.Item>
        </Form>
      </Modal>

      {/* 文献详情模态框 */}
      <Modal
        title="文献详情"
        visible={!!selectedLiterature}
        onCancel={() => setSelectedLiterature(null)}
        footer={null}
        width={800}
      >
        {selectedLiterature && (
          <div>
            <h3>{selectedLiterature.title}</h3>
            <p><strong>作者:</strong> {selectedLiterature.authors}</p>
            <p><strong>期刊:</strong> {selectedLiterature.journal}</p>
            <p><strong>年份:</strong> {selectedLiterature.publication_year}</p>
            <p><strong>DOI:</strong> {selectedLiterature.doi}</p>
            <p><strong>处理状态:</strong>
              <Tag color={getStatusColor(selectedLiterature.processing_status)}>
                {selectedLiterature.processing_status.toUpperCase()}
              </Tag>
            </p>
            <p><strong>提取置信度:</strong> {(selectedLiterature.extraction_confidence * 100).toFixed(1)}%</p>
            <p><strong>相关性评分:</strong> {(selectedLiterature.relevance_score * 100).toFixed(1)}%</p>

            {selectedLiterature.associated_formulas && selectedLiterature.associated_formulas.length > 0 && (
              <div style={{ marginTop: 16 }}>
                <h4>关联配方:</h4>
                {selectedLiterature.associated_formulas.map((formula: any, index: number) => (
                  <Card key={index} size="small" style={{ marginBottom: 8 }}>
                    <p><strong>{formula.name}</strong></p>
                    <p>{formula.description}</p>
                    <p>相关性: {(formula.association_info?.relevance_score * 100).toFixed(1)}%</p>
                  </Card>
                ))}
              </div>
            )}
          </div>
        )}
      </Modal>
    </div>
  );
};

export default LiteraturePage;
